namespace Application.Features.Command;

/// <summary>
/// Command to propagate the current base form template state to all customer-assigned copies.
/// </summary>
/// <param name="FormId">The identifier of the base form template (must have no customer assignment).</param>
public record FormTemplatePropagateToCustomersCommand(int FormId)
    : IRequest<Result<FormTemplatePropagateToCustomersCommandResult>>;

/// <summary>
/// Result of propagating a base form template to customer copies.
/// </summary>
/// <param name="UpdatedCount">The number of customer form copies that were updated.</param>
public record FormTemplatePropagateToCustomersCommandResult(int UpdatedCount);

namespace Application.Features.Command;

/// <summary>
/// Propagates the base form template (metadata, roles, and fields) to all customer copies
/// linked via <see cref="FormTemplate.OrginalId"/>.
/// </summary>
/// <remarks>
/// <strong>Execution Flow:</strong>
/// <list type="number">
/// <item>Loads the base form and verifies it belongs to base data (<c>CustomerId</c> is null).</item>
/// <item>Finds all customer forms where <c>OrginalId</c> equals the base form identifier.</item>
/// <item>For each customer copy, synchronizes template properties, roles, and fields from the base form.</item>
/// <item>Remaps conditional and group field relationships using <c>OrginalId</c> as the stable key.</item>
/// <item>Returns the number of updated customer forms.</item>
/// </list>
/// </remarks>
public class FormTemplatePropagateToCustomersCommandHandler(IApplicationDbContext context)
    : IRequestHandler<FormTemplatePropagateToCustomersCommand, Result<FormTemplatePropagateToCustomersCommandResult>>
{
    /// <summary>
    /// Applies base form changes to every customer form derived from the specified base template.
    /// </summary>
    /// <param name="request">The command containing the base form identifier.</param>
    /// <param name="cancellationToken">Token to observe for cancellation requests.</param>
    /// <returns>
    /// A result whose <see cref="FormTemplatePropagateToCustomersCommandResult.UpdatedCount"/>
    /// contains the number of customer forms updated, or a domain/server error on failure.
    /// </returns>
    public async Task<Result<FormTemplatePropagateToCustomersCommandResult>> Handle(
        FormTemplatePropagateToCustomersCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var baseForm = await context.FormTemplates
                .Include(x => x.Roles)
                .Include(x => x.Fields)
                .FirstOrDefaultAsync(x => x.Id == request.FormId, cancellationToken);

            if (baseForm is null)
                return FormErrors.FormNotFound;

            if (baseForm.CustomerId.HasValue)
                return FormErrors.NotBaseForm;

            var customerForms = await context.FormTemplates
                .Include(x => x.Roles)
                .Include(x => x.Fields)
                .Where(x => x.OrginalId == request.FormId && x.CustomerId.HasValue)
                .ToListAsync(cancellationToken);

            foreach (var customerForm in customerForms)
                await SyncFormFromBaseAsync(baseForm, customerForm, cancellationToken);

            if (customerForms.Count > 0)
                await context.SaveChangesAsync(cancellationToken);

            return Result<FormTemplatePropagateToCustomersCommandResult>.Success(
                new FormTemplatePropagateToCustomersCommandResult(customerForms.Count));
        }
        catch (Exception ex)
        {
            Log.Error($"PropagateBaseFormToCustomers: {ex.Message}", ex);
            return Error.ServerError;
        }
    }

    private async Task SyncFormFromBaseAsync(
        FormTemplate baseForm,
        FormTemplate customerForm,
        CancellationToken cancellationToken)
    {
        CopyTemplateProperties(baseForm, customerForm);
        SyncRoles(baseForm, customerForm);

        var baseFields = baseForm.Fields
            .OrderBy(x => x.NO)
            .ThenBy(x => x.Id)
            .ToList();

        var baseFieldIds = baseFields.Select(x => x.Id).ToHashSet();
        var fieldMap = new Dictionary<int, FormField>();

        foreach (var baseField in baseFields)
        {
            var customerField = customerForm.Fields
                .FirstOrDefault(x => x.OrginalId == baseField.Id);

            if (customerField is null)
            {
                customerField = new FormField
                {
                    FormId = customerForm.Id,
                    OrginalId = baseField.Id,
                };
                customerForm.Fields.Add(customerField);
                context.FormFields.Add(customerField);
            }

            CopyFieldProperties(baseField, customerField);
            fieldMap[baseField.Id] = customerField;
        }

        foreach (var customerField in customerForm.Fields.ToList())
        {
            if (customerField.OrginalId <= 0)
                continue;

            if (!baseFieldIds.Contains(customerField.OrginalId))
                RemoveFieldWithGroupChildren(customerField);
        }

        await context.SaveChangesAsync(cancellationToken);

        foreach (var baseField in baseFields)
        {
            if (!fieldMap.TryGetValue(baseField.Id, out var customerField))
                continue;

            customerField.ParentFieldId = null;
            customerField.GroupId = null;

            if (baseField.ParentFieldId.HasValue
                && fieldMap.TryGetValue(baseField.ParentFieldId.Value, out var parentField))
            {
                customerField.ParentFieldId = parentField.Id;
            }

            if (baseField.GroupId.HasValue
                && fieldMap.TryGetValue(baseField.GroupId.Value, out var groupField))
            {
                customerField.GroupId = groupField.Id;
            }
        }
    }

    private static void CopyTemplateProperties(FormTemplate source, FormTemplate target)
    {
        target.Name = source.Name;
        target.Description = source.Description;
        target.Code = source.Code;
        target.ProjectName = source.ProjectName;
        target.LastRevisedDate = source.LastRevisedDate;
        target.Link = source.Link;
        target.LinkText = source.LinkText;
        target.CategoryId = source.CategoryId;
        target.Type = source.Type;
        target.NO = source.NO;
        target.Files = source.Files.ToList();
    }

    private void SyncRoles(FormTemplate source, FormTemplate target)
    {
        var sourceRoleIds = source.Roles.Select(x => x.RoleId).ToHashSet();

        foreach (var role in target.Roles.ToList())
        {
            if (!sourceRoleIds.Contains(role.RoleId))
                context.FormRoles.Remove(role);
        }

        foreach (var roleId in sourceRoleIds)
        {
            if (!target.Roles.Any(x => x.RoleId == roleId))
                target.Roles.Add(new FormRole { RoleId = roleId, FormId = target.Id });
        }
    }

    private static void CopyFieldProperties(FormField source, FormField target)
    {
        target.Name = source.Name;
        target.Description = source.Description;
        target.CalculateCount = source.CalculateCount;
        target.Lines = source.Lines;
        target.DefaultValue = source.DefaultValue;
        target.NO = source.NO;
        target.IsActive = source.IsActive;
        target.Force = source.Force;
        target.Level = source.Level;
        target.IsSpecial = source.IsSpecial;
        target.ParentValue = source.ParentValue;
        target.Type = source.Type;
        target.Options = source.Options.ToList();
    }

    private void RemoveFieldWithGroupChildren(FormField field)
    {
        if (field.Type == FormFieldType.Group)
        {
            foreach (var child in field.GroupChildren.ToList())
                context.FormFields.Remove(child);
        }

        context.FormFields.Remove(field);
    }
}

