namespace Application.Models;

/// <summary>
/// Represents a customer that has an assigned copy of a base form template.
/// </summary>
public record FormPropagateTargetModel
{
    /// <summary>Gets or sets the customer identifier.</summary>
    public int CustomerId { get; set; }

    /// <summary>Gets or sets the customer display name.</summary>
    public string CustomerName { get; set; } = string.Empty;

    /// <summary>Gets or sets whether the customer's copy of the form is active.</summary>
    public bool IsActive { get; set; }
}

namespace Application.Features.Query;

/// <summary>
/// Query to list customers that have a copy of the specified base form template.
/// </summary>
/// <param name="FormId">The base form template identifier.</param>
public record FormTemplatePropagateTargetsQuery(int FormId)
    : IRequest<Result<FormTemplatePropagateTargetsQueryResult>>;

/// <summary>
/// Result containing customers eligible for propagation of a base form.
/// </summary>
/// <param name="Targets">Customers with an assigned copy linked via <c>OrginalId</c>.</param>
public record FormTemplatePropagateTargetsQueryResult(List<FormPropagateTargetModel> Targets);

namespace Application.Features.Query;

/// <summary>
/// Returns customers that have a form copy derived from the specified base template.
/// </summary>
public class FormTemplatePropagateTargetsQueryHandler(IApplicationDbContext context)
    : IRequestHandler<FormTemplatePropagateTargetsQuery, Result<FormTemplatePropagateTargetsQueryResult>>
{
    /// <summary>
    /// Loads customers with assigned copies of the base form.
    /// </summary>
    /// <param name="request">The query containing the base form identifier.</param>
    /// <param name="cancellationToken">Token to observe for cancellation requests.</param>
    /// <returns>
    /// A list of <see cref="FormPropagateTargetModel"/> entries on success,
    /// or a domain/server error on failure.
    /// </returns>
    public async Task<Result<FormTemplatePropagateTargetsQueryResult>> Handle(
        FormTemplatePropagateTargetsQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            var baseForm = await context.FormTemplates
                .AsNoTracking()
                .FirstOrDefaultAsync(x => x.Id == request.FormId, cancellationToken);

            if (baseForm is null)
                return FormErrors.FormNotFound;

            if (baseForm.CustomerId.HasValue)
                return FormErrors.NotBaseForm;

            var targets = await context.FormTemplates
                .AsNoTracking()
                .Where(x => x.OrginalId == request.FormId && x.CustomerId.HasValue)
                .Join(
                    context.Customers.AsNoTracking(),
                    form => form.CustomerId!.Value,
                    customer => customer.Id,
                    (form, customer) => new FormPropagateTargetModel
                    {
                        CustomerId = customer.Id,
                        CustomerName = customer.Name,
                        IsActive = form.IsActive,
                    })
                .OrderBy(x => x.CustomerName)
                .ToListAsync(cancellationToken);

            return Result<FormTemplatePropagateTargetsQueryResult>.Success(
                new FormTemplatePropagateTargetsQueryResult(targets));
        }
        catch (Exception ex)
        {
            Log.Error($"FormTemplatePropagateTargets: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

namespace Application.Features.Command;

