namespace UI.Component.Pages;

/// <summary>
/// View model for selecting customers before propagating base form changes.
/// </summary>
public class FormPropagateCustomersDialogViewModel(ISender sender)
    : BaseViewModel<List<FormPropagateTargetModel>>
{
    /// <summary>Gets or sets the base form template identifier.</summary>
    internal int FormId { get; set; }

    /// <summary>Gets the set of selected customer identifiers.</summary>
    internal HashSet<int> SelectedCustomerIds { get; } = [];

    /// <summary>Gets whether every loaded customer is currently selected.</summary>
    internal bool IsAllSelected =>
        Model is { Count: > 0 } && SelectedCustomerIds.Count == Model.Count;

    /// <summary>
    /// Loads customers that have a copy of the base form assigned.
    /// </summary>
    /// <returns>The list of propagation targets.</returns>
    public override async Task<List<FormPropagateTargetModel>> LoadDataAsync()
    {
        Loading();
        Message = string.Empty;

        var res = await sender.Send(new FormTemplatePropagateTargetsQuery(FormId));

        IsSuccess = res.Match(
            onSuccess: model =>
            {
                Model = model.Targets;
                SelectedCustomerIds.Clear();
                foreach (var target in Model.Where(x => x.IsActive))
                    SelectedCustomerIds.Add(target.CustomerId);
            },
            onFailure: error => Message = error.Description);

        if (Model is null)
            Model = [];

        Loaded();
        return Model;
    }

    /// <summary>Selects or clears all customers in the list.</summary>
    /// <param name="selectAll">True to select all; false to clear selection.</param>
    internal void SetSelectAll(bool selectAll)
    {
        SelectedCustomerIds.Clear();

        if (selectAll)
        {
            foreach (var target in Model)
                SelectedCustomerIds.Add(target.CustomerId);
        }
    }

    /// <summary>Toggles selection for a single customer.</summary>
    /// <param name="customerId">The customer identifier.</param>
    /// <param name="selected">True when the customer should be selected.</param>
    internal void SetCustomerSelected(int customerId, bool selected)
    {
        if (selected)
            SelectedCustomerIds.Add(customerId);
        else
            SelectedCustomerIds.Remove(customerId);
    }

    /// <summary>Gets the display names of currently selected customers.</summary>
    internal IEnumerable<string> SelectedCustomerNames =>
        Model.Where(x => SelectedCustomerIds.Contains(x.CustomerId))
            .Select(x => x.CustomerName);
}

